package com.google.gson.metrics;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.Field;
import java.lang.reflect.Method;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

public class ParseBenchmarkTest {

  private ParseBenchmark parseBenchmark;

  @BeforeEach
  void init() {
    parseBenchmark = new ParseBenchmark();
  }

  @Test
  void testSetUp() throws Exception {
    // Use reflection to get the Class objects of the private inner classes Document and Api
    Class<?> documentClass = null;
    Class<?> apiClass = null;
    for (Class<?> innerClass : ParseBenchmark.class.getDeclaredClasses()) {
      if ("Document".equals(innerClass.getSimpleName())) {
        documentClass = innerClass;
      } else if ("Api".equals(innerClass.getSimpleName())) {
        apiClass = innerClass;
      }
    }
    assertNotNull(documentClass, "Document class not found");
    assertNotNull(apiClass, "Api class not found");

    // Mock Document enum with name() returning "testdoc"
    Object mockDocument = mock(documentClass);
    when(mockDocument.getClass().getMethod("name").invoke(mockDocument)).thenReturn("testdoc");
    // Since above won't work, use Mockito.when(mockDocument.name()) via reflection:
    // Instead, use Mockito's when with reflection proxy:
    // So mockDocument is a mock of documentClass, so we can do:
    when(documentClass.getMethod("name").invoke(mockDocument)).thenReturn("testdoc"); // won't work directly
    // Instead use doReturn:
    // but best to use Mockito's when with invocation handler:
    // So let's use Mockito's when with reflection:
    // Actually, simpler to create a mock with RETURNS_DEFAULTS and stub the name method via Mockito:
    // We'll create the mock with RETURNS_DEEP_STUBS and stub name method:
    // But since name() is final in enum, mocking it may fail.
    // So better to create a dynamic proxy object or a subclass via reflection.

    // Instead, create a proxy for Document that overrides name():
    Object mockDocumentProxy = java.lang.reflect.Proxy.newProxyInstance(
        documentClass.getClassLoader(),
        new Class<?>[]{documentClass},
        (proxy, method, args) -> {
          if ("name".equals(method.getName())) {
            return "testdoc";
          }
          return method.getDefaultValue();
        });

    // Mock Api with newParser() returning a mock Parser
    Object mockApi = mock(apiClass);
    // Get Parser class similarly
    Class<?> parserClass = null;
    for (Class<?> innerClass : ParseBenchmark.class.getDeclaredClasses()) {
      if ("Parser".equals(innerClass.getSimpleName())) {
        parserClass = innerClass;
        break;
      }
    }
    assertNotNull(parserClass, "Parser class not found");
    Object mockParser = mock(parserClass);
    Method newParserMethod = apiClass.getMethod("newParser");
    when(newParserMethod.invoke(mockApi)).thenReturn(mockParser);
    // Above won't work because when() expects a method call on a mock, not reflection invoke.
    // So instead, stub newParser() with Mockito:
    when(((ParseBenchmark.Api) mockApi).newParser()).thenReturn((ParseBenchmark.Parser) mockParser);
    // But we can't cast because Api and Parser are private.
    // So instead, use Mockito's stub via doReturn:
    // But still need to cast to Object and use Mockito's when(Object.method()) won't work.
    // So use Mockito's doReturn:
    // But doReturn also requires method call.
    // So use Mockito's Answer:
    // Alternatively, use Mockito's stub via Mockito.mock with Answers:
    // Instead, create a mock Api with a custom Answer:
    mockApi = mock(apiClass, invocation -> {
      if ("newParser".equals(invocation.getMethod().getName())) {
        return mockParser;
      }
      return invocation.callRealMethod();
    });

    // Set private fields document and api
    setField(parseBenchmark, "document", mockDocumentProxy);
    setField(parseBenchmark, "api", mockApi);

    // Mock static method resourceToString to return known string
    try (MockedStatic<ParseBenchmark> mockedStatic = Mockito.mockStatic(ParseBenchmark.class)) {
      mockedStatic.when(() -> {
        try {
          Method resourceToStringMethod = ParseBenchmark.class.getDeclaredMethod("resourceToString", String.class);
          resourceToStringMethod.setAccessible(true);
          return resourceToStringMethod.invoke(null, "testdoc.json");
        } catch (Exception e) {
          throw new RuntimeException(e);
        }
      }).thenReturn("jsoncontent");

      // Invoke private method setUp() via reflection
      Method setUpMethod = ParseBenchmark.class.getDeclaredMethod("setUp");
      setUpMethod.setAccessible(true);
      setUpMethod.invoke(parseBenchmark);

      // Verify that resourceToString was called correctly
      mockedStatic.verify(() -> {
        try {
          Method resourceToStringMethod = ParseBenchmark.class.getDeclaredMethod("resourceToString", String.class);
          resourceToStringMethod.setAccessible(true);
          return resourceToStringMethod.invoke(null, "testdoc.json");
        } catch (Exception e) {
          throw new RuntimeException(e);
        }
      });

      // Verify fields text and parser are set correctly
      char[] text = (char[]) getField(parseBenchmark, "text");
      assertArrayEquals("jsoncontent".toCharArray(), text);

      Object parser = getField(parseBenchmark, "parser");
      assertSame(mockParser, parser);
    }
  }

  // Helper method to set private field via reflection
  private static void setField(Object target, String fieldName, Object value) throws Exception {
    Field field = target.getClass().getDeclaredField(fieldName);
    field.setAccessible(true);
    field.set(target, value);
  }

  // Helper method to get private field via reflection
  private static Object getField(Object target, String fieldName) throws Exception {
    Field field = target.getClass().getDeclaredField(fieldName);
    field.setAccessible(true);
    return field.get(target);
  }
}
